use std::collections::HashMap;

struct ProcessedItem {
    id: u32,
    content: String,
    references: Vec<u32>,
}

impl ProcessedItem {
    fn new(id: u32, content: &str) -> Self {
        ProcessedItem { id, content: content.to_string(), references: Vec::new() }
    }
}

struct TemplateEngine {
    items: HashMap<u32, ProcessedItem>,
    next_id: u32,
}

impl TemplateEngine {
    fn new() -> Self {
        TemplateEngine { items: HashMap::new(), next_id: 0 }
    }

    fn add_item(&mut self, content: &str) -> u32 {
        let id = self.next_id;
        self.items.insert(id, ProcessedItem::new(id, content));
        self.next_id += 1;
        id
    }

    fn link_item(&mut self, source_id: u32, target_id: u32) -> Result<(), &'static str> {
        if !self.items.contains_key(&source_id) || !self.items.contains_key(&target_id) {
            return Err("One or both IDs do not exist in the template.");
        }

        let item = self.items.get_mut(&source_id).unwrap();
        if !item.references.contains(&target_id) {
            item.references.push(target_id);
        }
        Ok(())
    }

    fn get_total_items(&self) -> usize {
        self.items.len()
    }
}

fn main() {
    let mut engine = TemplateEngine::new();
    let id1 = engine.add_item("Title Block");
    let id2 = engine.add_item("Main Body Content");
    let id3 = engine.add_item("Footer Signature");

    engine.link_item(id1, id2).unwrap();
    engine.link_item(id2, id3).unwrap();

    println!("Engine initialized with {} total items.", engine.get_total_items());
    let final_check = match engine.items.get(&id1) { 
        Some(item) => format!("Item 1 references: {:?}", item.references), 
        None => "Failed to retrieve Item 1".to_string() 
    };
    println!("{}", final_check);
}

