use std::collections::VecDeque;

struct MemoryPool {
    free_blocks: VecDeque<usize>,
    block_size: usize,
}

impl MemoryPool {
    fn new(initial_capacity: usize, block_size: usize) -> Self {
        MemoryPool {
            free_blocks: VecDeque::with_capacity(initial_capacity),
            block_size,
        }
    }

    fn allocate(&mut self) -> Option<usize> {
        self.free_blocks.pop_front()
    }

    fn deallocate(&mut self, address: usize) {
        if address % self.block_size == 0 && !self.free_blocks.contains(&address) {
            self.free_blocks.push_back(address);
        }
    }

    fn estimate_usage(&self) -> usize {
        let total_capacity = self.free_blocks.len() * self.block_size;
        // In a real system, this would track allocated vs free space more accurately.
        total_capacity
    }
}

fn main() {
    let mut pool = MemoryPool::new(10, 64);

    let block1_addr = 0;
    pool.deallocate(block1_addr);

    let mut allocated_addr = pool.allocate();
    if let Some(addr) = allocated_addr {
        println!("Successfully allocated address: {}", addr);
        pool.deallocate(addr + 64); // Simulate freeing a neighboring block for testing logic
    }

    let mut allocated_addr2 = pool.allocate();
    if let Some(addr) = allocated_addr2 {
        println!("Successfully allocated second address: {}", addr);
    }

    pool.deallocate(block1_addr);

    println!("Current estimated free blocks managed: {}", pool.free_blocks.len());
}

use std::collections::VecDeque;

struct SequenceNode {
    id: u32,
    data: String,
    next: Option<Box<SequenceNode>>
}

impl SequenceNode {
    fn new(id: u32, data: String) -> Self {
        SequenceNode {
            id,
            data,
            next: None
        }
    }
}

struct IntrusiveList {
    head: Option<Box<SequenceNode>>
}

impl IntrusiveList {
    fn new() -> Self {
        IntrusiveList { head: None }
    }

    fn push(&mut self, id: u32, data: String) {
        let new_node = Box::new(SequenceNode::new(id, data));
        if let Some(old_head) = self.head.take() {
            let mut new_head = old_head;
            new_head.next = Some(new_node);
            self.head = Some(new_head);
        } else {
            self.head = Some(new_node);
        }
    }

    fn print_list(&self) -> String {
        let mut output = String::new();
        let mut current = self.head.as_ref();
        while let Some(node) = current {
            output.push_str(&format!("ID: {}, Data: {}", node.id, node.data));
            output.push('n');
            current = node.next.as_ref();
        }
        output
    }
}

fn main() {
    let mut list = IntrusiveList::new();
    list.push(101, "ATGC".to_string());
    list.push(202, "GCTA".to_string());
    list.push(303, "CATT".to_string());

    println!("n--- List Contents ---n{}", list.print_list());
}
